--
-- TOC entry 247 (class 1255 OID 16708)
-- Name: fdetalyes(character varying, character varying); Type: FUNCTION; Schema: ppe; Owner: -
--

CREATE FUNCTION ppe.fdetalyes(empid character varying, office character varying) RETURNS TABLE(qnty smallint, tyepo character varying, itemname character varying, subcatename character varying, categoria character varying, unitcost double precision, acquired date, uselife smallint)
    LANGUAGE sql STABLE PARALLEL SAFE
    AS $_$
	SELECT 
 		count(*) AS qnty,
    	disposition.tyepo,
		vcategorias.itemname,
		vcategorias.subcatename,
		vcategorias.categoria,
		disposition.unitcost,
		disposition.acquired,
		disposition.uselife
   	FROM
	   ppe.disposition INNER JOIN prc.vcategorias
	   ON disposition.subdtl = vcategorias.catdtld
	   INNER JOIN ppe.dispossessed 
	   ON dispossessed.wastedno = disposition.wastedno
	WHERE 
		(dispossessed.empkey = $1) AND
		(dispossessed.opesina = $2)
  	GROUP BY
  		disposition.tyepo,
		vcategorias.itemname,
		vcategorias.subcatename,
		vcategorias.categoria,
		disposition.unitcost,
		disposition.acquired,
		disposition.uselife;
$_$;


