-- Dependencies: 239
-- Name: COLUMN userlogs.permiso; Type: COMMENT; Schema: prc; Owner: -
--

COMMENT ON COLUMN prc.userlogs.permiso IS 'A ~ Price Watch
B ~ PPMP
C ~ Purchase Request';


--
-- TOC entry 240 (class 1259 OID 16816)
-- Name: vcategorias; Type: VIEW; Schema: prc; Owner: -
--

CREATE VIEW prc.vcategorias AS
 SELECT catdetails.catdtld,
    catdetails.itemname,
    catsiblings.subcat,
    catsiblings.subcatename,
    categories.cat_id,
    categories.categoria
   FROM ((prc.catdetails
     JOIN prc.catsiblings ON ((((catdetails.cat_id)::text = (catsiblings.cat_id)::text) AND ((catdetails.sub_cats)::text = (catsiblings.subcat)::text))))
     JOIN prc.categories ON (((catsiblings.cat_id)::text = (categories.cat_id)::text)));


